from ariadne import QueryType, make_executable_schema, gql, load_schema_from_path, ObjectType
from ariadne.asgi import GraphQL
from starlette.middleware.base import BaseHTTPMiddleware
from starlette.requests import Request
from starlette.responses import Response
import json

# Define schema
type_defs = gql("""
    type User {
        username: String!
        bio: String
        email: String
        phone: String
        address: String
    }

    type Post {
        title: String!
        content: String!
        author: User!
    }

    type Query {
        userProfile(username: String!): User
    }
""")

# Sample data
users = [
    {"username": "john_doe", "bio": "Software Developer", "email": "john@example.com", "phone": "1234567890", "address": "123 Main St"},
    {"username": "jane_smith", "bio": "Graphic Designer", "email": "jane@example.com", "phone": "0987654321", "address": "456 Elm St"}
]

# Resolvers
query = QueryType()

@query.field("userProfile")
def resolve_user_profile(_, info, username):
    current_user = info.context.get("current_user")
    user = next((user for user in users if user["username"] == username), None)
    if user and current_user == username:
        return user
    elif user:
        return {k: user[k] for k in user if k in ["username", "bio"]}
    return None

# Middleware for authentication
class AuthMiddleware(BaseHTTPMiddleware):
    async def dispatch(self, request: Request, call_next):
        # Simulate authentication
        request.state.current_user = request.headers.get("x-current-user")
        response = await call_next(request)
        return response

# Create executable schema
schema = make_executable_schema(type_defs, query)

# Create ASGI app
